mapper.select:
SELECT p.id id,d.id drug_info_id,d.drug_code item_code,d.drug_name item_name, d.drug_price item_price,p.drug_number item_number, "药品" as item_type,d.drug_format item_format, p.creation_time item_create_time, d.drug_unit drug_unit, d.manufacturer manufacturer, p.drug_state item_state FROM prescription p, drug_info d WHERE p.drug_id = d.id
AND p.drug_state=#{drug_state,jdbcType=VARCHAR}
AND p.register_id=#{register_id,jdbcType=INTEGER}

mapper.update:
UPDATE prescription
SET drug_state=#{drug_state,jdbcType=VARCHAR}
WHERE id=#{id,jdbcType=INTEGER}

UPDATE prescription
SET drug_state=#{newState,jdbcType=VARCHAR}
WHERE register_id=#{registerId,jdbcType=INTEGER}
	AND drug_state=#{currentState,jdbcType=VARCHAR}

mapper.select:
SELECT r.*
FROM register r , (select register_id,drug_state from prescription group by register_id,drug_state having drug_state =#{drug_state}) c
WHERE r.id = c.register_id
	AND date(visit_date) = date(now())

		AND r.case_number = #{case_number}


		AND r.real_name = #{real_name}

ORDER BY r.visit_date DESC
LIMIT ${(nowPageNumber-1) * pageSize} ,#{pageSize}

SELECT count(id)
FROM register r , (select register_id,drug_state from prescription group by register_id,drug_state having drug_state =#{drug_state}) c
WHERE r.id = c.register_id
	AND date(visit_date) = date(now())

		AND r.case_number = #{case_number}


		AND r.real_name = #{real_name}
